// Verify WaSender secret + extract the message. Two MEC groups are processed (set their JIDs in env):
//   MEC_ORDERS_GROUP_JID = the daily orders/chat group  -> group_type 'orders'
//   MEC_DOCS_GROUP_JID    = the invoices/documents group -> group_type 'docs'
// Direct messages stay group_type 'dm'. Any OTHER group is ignored. In a group the real author is
// key.participant (the sender) — that person is the SALESPERSON who brought the order.
const crypto = require('crypto');
const secret = $env.WASENDER_WEBHOOK_SECRET || '';
const ordersJid = String($env.MEC_ORDERS_GROUP_JID || '').trim();
const docsJid = String($env.MEC_DOCS_GROUP_JID || '').trim();
const item = $input.first().json;
const headers = item.headers || {};
const body = item.body || item;

const sig = headers['x-webhook-signature'] || headers['X-Webhook-Signature'] || '';
let verified = false;
try { const hmac = crypto.createHmac('sha256', secret).update(JSON.stringify(body)).digest('hex'); verified = Boolean(sig && (sig === secret || sig === hmac)); } catch (e) { verified = false; }

const ev = body.data || body;
const msg = ev.messages || ev.message || (ev.event === 'messages.upsert' ? ev.data : null) || ev;
const m = Array.isArray(msg) ? msg[0] : msg;
if (!m) return [];
if (m.key && m.key.fromMe) return [];            // ignore our own outgoing

const remoteJid = (m.key && m.key.remoteJid) || m.from || m.chatId || ev.from || '';
if (/status@broadcast/.test(remoteJid)) return [];
const isGroup = /@g\.us/.test(remoteJid);

let group_type = 'dm';
if (isGroup) {
  if (ordersJid && remoteJid === ordersJid) group_type = 'orders';
  else if (docsJid && remoteJid === docsJid) group_type = 'docs';
  else group_type = 'unknown';                    // record it so its group_jid shows in the inbox (setup), but don't process as an order/doc
}

const participant = (m.key && m.key.participant) || m.participant || '';
const senderJid = isGroup ? participant : remoteJid;
const senderPhone = String(senderJid).replace(/@s\.whatsapp\.net$/, '').replace(/@g\.us$/, '');
const senderName = m.pushName || ev.pushName || '';

let content = m.message || {};
// Unwrap WhatsApp envelopes so the real content is seen — forwarded PDFs/images-with-caption,
// disappearing (ephemeral) and view-once messages all nest the actual message one level down.
content = (content.ephemeralMessage && content.ephemeralMessage.message)
  || (content.viewOnceMessage && content.viewOnceMessage.message)
  || (content.viewOnceMessageV2 && content.viewOnceMessageV2.message)
  || (content.documentWithCaptionMessage && content.documentWithCaptionMessage.message)
  || content;
const docMsg = content.documentMessage || null;
const imgMsg = content.imageMessage || null;
// For a document the file name/title is the best signal of what it is (e.g. "فاتورة ... 389.pdf").
const text = content.conversation
  || (content.extendedTextMessage && content.extendedTextMessage.text)
  || (imgMsg && imgMsg.caption)
  || (docMsg && (docMsg.caption || docMsg.title || docMsg.fileName))
  || m.text || m.body || '';
let type = 'text';
if (imgMsg || m.type === 'image') type = 'image';
else if (docMsg) type = 'document';
else if (content.audioMessage) type = 'audio';
else if (content.reactionMessage) type = 'reaction';

// A reaction (e.g. a ✅ on the order message) carries the emoji + the id of the message it reacts to.
const reaction = content.reactionMessage || {};
const reaction_emoji = reaction.text || '';
const reaction_target = (reaction.key && reaction.key.id) || '';

// Drop only pure system/encryption noise (key exchange, protocol). EVERYTHING else — including ordinary
// chatter — is saved so the admin can audit exactly what JARVIS read; chatter is classified intent=other
// and the order guard means it never becomes an order.
const _realKeys = Object.keys(content).filter(k => !['messageContextInfo', 'senderKeyDistributionMessage', 'protocolMessage'].includes(k));
if (!text && _realKeys.length === 0) return [];

// Quoted/replied message id — threads an approval / rejection / quantity adjustment back to the order.
const ctx = (content.extendedTextMessage && content.extendedTextMessage.contextInfo)
  || (imgMsg && imgMsg.contextInfo)
  || (docMsg && docMsg.contextInfo) || {};
const quoted_message_id = ctx.stanzaId || ctx.quotedMessageId || '';

return [{ json: {
  message_id: (m.key && m.key.id) || m.id || `${remoteJid}-${m.messageTimestamp || ''}`,
  group_jid: isGroup ? remoteJid : '',
  group_type,
  phone: senderPhone,
  push_name: senderName,
  salesperson: senderName,
  body: text,
  message_type: type,
  media_url: (docMsg && docMsg.url) || (imgMsg && imgMsg.url) || m.mediaUrl || '',
  quoted_message_id,
  reaction_emoji,
  reaction_target,
  verified,
  raw: body
}}];

// Classify the message. DOCUMENTS/IMAGES are READ by GPT-4o (it sees stamps, prices, bank details so a
// stamped-as-received invoice is recognised as a delivery note); text/chatter uses the cheap model; a
// reaction needs no classification.
const src = $('Verify + extract').item.json;
const oaiKey = $env.OPENAI_API_KEY || '';
const helpers = this.helpers;
const isFile = (src.message_type === 'document' || src.message_type === 'image');
let cls = {};
// OWNER STATUS BOT: a greeting/'report' DM from an owner number triggers a full portal status report (the
// portal builds it + sends it back via WaSender). Handled before any other classification.
const OWNER_NUMS = ['966500900377','966556732109','966540747300'];
// WhatsApp now hides the number behind an @lid privacy id, so read the REAL number from key.cleanedSenderPn.
const _rm = (src.raw && src.raw.data && src.raw.data.messages) || (src.raw && src.raw.messages) || {};
const _k = _rm.key || {};
const _from = String(_k.cleanedSenderPn || _k.senderPn || src.phone || '').replace(/@.*/, '').replace(/[^0-9]/g, '');
const _isOwner = OWNER_NUMS.some(n => _from.length >= 9 && _from.endsWith(n.slice(-9)));
const _b = String(src.body||'').toLowerCase().trim();
const _isStatusReq = _b.includes('jarvis')||_b.includes('جارفيس')||_b.includes('report')||_b.includes('تقرير')||_b.includes('status')||_b.includes('الحالة')||(_b.length<=15 && (_b.includes('hi')||_b.includes('hello')||_b.includes('hey')||_b.includes('مرحبا')||_b.includes('اهلا')||_b.includes('أهلا')||_b.includes('السلام')||_b.includes('هلا')));
const _isDM = (src.group_type !== 'orders' && src.group_type !== 'docs');
if (_isOwner && _isDM && _isStatusReq && src.message_type !== 'reaction') {
  try { await helpers.httpRequest({ method: 'GET', url: ($env.PORTAL_BASE_URL) + '/api/jarvis-status?key=' + encodeURIComponent($env.WASENDER_WEBHOOK_SECRET) + '&send=1&to=' + _from, json: true }); } catch (e) {}
  return [{ json: { cls: { intent: 'other' }, status_replied: true } }];
}
const DOC_PROMPT = "You are reading a business document for MEC, a food distributor in Saudi Arabia. It may be a PDF or a photo/scan, Arabic or English. FIRST, look carefully for any STAMP, SIGNATURE, or handwriting showing the CLIENT RECEIVED the goods - for example تم الاستلام, استلمت, مستلم, received, or delivered, or a delivery/receipt stamp or signature. RULE: if such a received mark appears ANYWHERE, even on an invoice layout, the document is a DELIVERY NOTE, because a stamped-as-received invoice IS the delivery note. If there is NO received mark: a فاتورة with prices or VAT is an invoice; a purchase order (أمر شراء) is po; a bank transfer, deposit, or payment receipt is payment; a RECEIVABLES/CREDIT statement (titled المديونية, or a table listing clients with outstanding amounts and aging أعمار الذمم) is credit; an INVENTORY/STOCK count (titled المخزون, or a list of products with quantities/cartons on hand) is inventory. These last two are team status reports from staff, not order documents - never treat them as invoices. Anything else is other. If doc_type is credit, ALSO read the whole table into extracted as an array of {date (the invoice date as YYYY-MM-DD), invoiceNo, client, salespersonAr, amount (number, the after-tax/المبلغ بعد الضريبة amount), ageDays (number, اعمار الذمم)} - one object per row, skip the totals row. If doc_type is inventory, set extracted to an array of {item, cartons (number)} - one per product row, skip subtotal/الإجمالي rows. Otherwise extracted is null. Reply ONLY with a JSON object with these fields: doc_type (one of invoice, delivery_note, payment, po, credit, inventory, other), received_stamp (true or false), order_no (the order or invoice number, or null), client (the client or company name, or null), recipient (the receiver named, or null), extracted (array or null), summary (one short line).";
const TEXT_PROMPT = "You triage WhatsApp TEXT messages for MEC, a food distributor in Saudi Arabia, Arabic or English. Most messages are ordinary chatter, greetings, thanks, or coordination - for those use intent other and extract nothing. A CLEAR order that lists products and quantities is intent order - extract the products as a list of name, qty, unit, plus order_no, client, and recipient (المستلم) if present. If reply_to=yes and the message approves an earlier order (موافق, تمام, تم, approved, اعتمد) set decision approve; if it rejects (مرفوض, لا, rejected, إلغاء) set decision reject; if it changes the quantities set decision adjust and put the NEW quantities in products. A PAYMENT or bank-transfer confirmation (إيداع, حوالة واردة, تحويل, سند قبض, or an amount with a bank and IBAN) has doc_type payment. IMPORTANT: invoices and delivery notes are always FILES, never plain text, so never set those from text. Reply ONLY with a JSON object with fields: intent (order, inquiry, complaint, approval, or other), order_no, client, recipient, products (array of name, qty, unit), doc_type (payment or null), decision (approve, reject, adjust, or null), summary.";
async function ask(body){ try { const r = await helpers.httpRequest({ method: 'POST', url: 'https://api.openai.com/v1/chat/completions', headers: { Authorization: 'Bearer ' + oaiKey, 'Content-Type': 'application/json' }, body: body, json: true }); return JSON.parse(r.choices[0].message.content); } catch (e) { return {}; } }
if (src.message_type === 'reaction') {
  cls = {};
} else if (isFile) {
  try {
    const crypto = require('crypto');
    const raw = src.raw || {};
    const root = (raw.data && raw.data.messages && raw.data.messages.message) || (raw.messages && raw.messages.message) || raw.message || raw;
    let media = null, kind = null;
    const find = (n) => { if (!n || typeof n !== 'object' || media) return; if (n.documentMessage) { media = n.documentMessage; kind = 'document'; return; } if (n.imageMessage) { media = n.imageMessage; kind = 'image'; return; } for (const k of Object.keys(n)) find(n[k]); };
    find(root);
    if (media && media.url && media.mediaKey) {
      const INFO = { image: 'WhatsApp Image Keys', document: 'WhatsApp Document Keys', video: 'WhatsApp Video Keys', audio: 'WhatsApp Audio Keys' };
      const mk = Buffer.from(media.mediaKey, 'base64');
      const exp = Buffer.from(crypto.hkdfSync('sha256', mk, Buffer.alloc(0), Buffer.from(INFO[kind]), 112));
      const encResp = await helpers.httpRequest({ url: media.url, encoding: 'arraybuffer' });
      const enc = Buffer.isBuffer(encResp) ? encResp : Buffer.from(encResp);
      const d = crypto.createDecipheriv('aes-256-cbc', exp.subarray(16, 48), exp.subarray(0, 16));
      const fileBuf = Buffer.concat([d.update(enc.subarray(0, enc.length - 10)), d.final()]);
      const mime = media.mimetype || (kind === 'image' ? 'image/jpeg' : 'application/pdf');
      const dataUrl = 'data:' + mime + ';base64,' + fileBuf.toString('base64');
      const isImg = kind === 'image' || (mime && mime.slice(0, 6) === 'image/');
      const part = isImg ? { type: 'image_url', image_url: { url: dataUrl } } : { type: 'file', file: { filename: media.fileName || media.title || 'document.pdf', file_data: dataUrl } };
      cls = await ask({ model: 'gpt-4o', temperature: 0, response_format: { type: 'json_object' }, messages: [ { role: 'user', content: [ { type: 'text', text: DOC_PROMPT }, part ] } ] });
      cls.intent = 'other';
    } else {
      cls = { intent: 'other', doc_type: 'other' };
    }
  } catch (e) {
    cls = { intent: 'other', doc_type: 'other' };
  }
} else {
  cls = await ask({ model: $env.OPENAI_BATCH_MODEL || 'gpt-4o-mini', temperature: 0, response_format: { type: 'json_object' }, messages: [ { role: 'system', content: TEXT_PROMPT }, { role: 'user', content: 'group=' + String(src.group_type || 'dm') + ' | reply_to=' + (src.quoted_message_id ? 'yes' : 'no') + ' | ' + String(src.body || '(no text)') } ] });
}
return [{ json: { cls: cls } }];

// Merge extraction + classification into the Supabase row.
const cls = $json.cls || {};
const src = $('Verify + extract').item.json;
const isDoc = (src.message_type === 'document' || src.message_type === 'image');
let decision = (cls.decision && cls.decision !== 'null') ? cls.decision : null;
// A ✅ / 👍 reaction on the order approves it; a ❌ / 👎 rejects it — applied to the reacted message.
const emoji = String(src.reaction_emoji || '');
if (src.reaction_target) {
  if (/[\u2705\u2714\u2611\uD83D\uDC4D\uD83C\uDD97]/.test(emoji)) decision = 'approve';
  else if (/[\u274C\u2716\uD83D\uDC4E\uD83D\uDEAB\u26D4]/.test(emoji)) decision = 'reject';
  else decision = null;
}
// The order this decision targets: a reaction's target, else a quoted reply's target.
const target = src.reaction_target || src.quoted_message_id || null;
// Documents are FILES (a PDF or a photo of a signed/stamped invoice / delivery note / payment). A plain
// TEXT message that merely says a document was sent (e.g. "السند مرسل") is NOT the document — only an
// actual attachment counts. So doc_type is taken ONLY from a document/image message.
const docFromFile = isDoc ? ((cls.doc_type && cls.doc_type !== 'null') ? cls.doc_type : 'other') : (cls.doc_type === 'payment' ? 'payment' : null);
// A brand-new order (orders group, real content, no reply, no decision) starts pending. A DOCUMENT is
// never an order, an empty message is never an order, and a decision (reply OR reaction) updates the
// targeted order rather than opening a new one (handled in 'Apply order decision').
let order_status = null;
if (src.group_type === 'orders' && cls.intent === 'order' && !docFromFile && (src.body || (cls.products || []).length) && !decision && !target) order_status = 'pending';
return [{ json: {
  message_id: src.message_id,
  group_jid: src.group_jid || null,
  group_type: src.group_type,
  phone: src.phone,
  push_name: src.push_name,
  salesperson: src.salesperson || src.push_name || null,
  body: src.message_type === 'reaction' ? ('reacted ' + emoji).trim() : src.body,
  message_type: src.message_type,
  media_url: src.media_url,
  intent: cls.intent || 'other',
  order_no: (cls.order_no && cls.order_no !== 'null') ? String(cls.order_no) : null,
  client_name: (cls.client && cls.client !== 'null') ? cls.client : null,
  recipient: (cls.recipient && cls.recipient !== 'null') ? cls.recipient : null,
  products: cls.products || [],
  doc_type: docFromFile,
  quoted_message_id: target,
  decision,
  order_status,
  extracted: (cls.extracted && Array.isArray(cls.extracted) && cls.extracted.length) ? cls.extracted : null,
  raw: src.raw,
  verified: src.verified,
  received_at: $now.toISO()
}}];

// If this message is a REPLY that approves / rejects / adjusts an order, patch the quoted order row
// so the portal's approval queue updates automatically (the same as pressing Approve/Reject in-app).
const row = $('Build row').item.json;
const base = String($env.NEXT_PUBLIC_SUPABASE_URL || '').replace(/\/+$/, '');
const key = $env.SUPABASE_SERVICE_ROLE_KEY || '';
if (row.decision && row.quoted_message_id && base && key) {
  const patch = {};
  if (row.decision === 'approve') patch.order_status = 'approved';
  else if (row.decision === 'reject') patch.order_status = 'rejected';
  else if (row.decision === 'adjust') { patch.order_status = 'pending'; if ((row.products || []).length) patch.products = row.products; }
  if (Object.keys(patch).length) {
    try {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: base + '/rest/v1/whatsapp_intake?message_id=eq.' + encodeURIComponent(row.quoted_message_id),
        headers: { apikey: key, Authorization: 'Bearer ' + key, 'Content-Type': 'application/json', Prefer: 'return=minimal' },
        body: JSON.stringify(patch)
      });
    } catch (e) {}
  }
}
return [{ json: row }];

// Auto-reply is DISABLED for now — JARVIS listens silently and never sends a WhatsApp message,
// in groups OR direct chats. It only reads/records. To re-enable a DM-only acknowledgement later, set
// env WASENDER_AUTO_REPLY=1 (it will still never reply inside a group).
const row = $('Build row').item.json;
const replyOn = String($env.WASENDER_AUTO_REPLY || '') === '1';
if (replyOn && row.group_type === 'dm' && row.phone) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://wasenderapi.com/api/send-message',
      headers: { Authorization: 'Bearer ' + ($env.WASENDER_API_TOKEN || ''), 'Content-Type': 'application/json' },
      body: JSON.stringify({ to: row.phone, text: 'تم استلام رسالتك ✅ سيتواصل معك فريق MEC قريبًا. / Your message was received — MEC will get back to you shortly.' })
    });
  } catch (e) {}
}
return [{ json: row }];
